{"meta": null, "content": [{"type": "text", "text": "{"content":"1: #include \"source/common/config/subscription_factory_impl.h\"\n2: \n3: #include \"envoy/config/core/v3/config_source.pb.h\"\n4: #include \"envoy/config/xds_resources_delegate.h\"\n5: \n6: #include \"source/common/config/custom_config_validators_impl.h\"\n7: #include \"source/common/config/type_to_endpoint.h\"\n8: #include \"source/common/config/utility.h\"\n9: #include \"source/common/config/xds_resource.h\"\n10: #include \"source/common/http/utility.h\"\n11: #include \"source/common/protobuf/protobuf.h\"\n12: #include \"source/common/protobuf/utility.h\"\n13: \n14: namespace Envoy {\n15: namespace Config {\n16: \n17: SubscriptionFactoryImpl::SubscriptionFactoryImpl(\n18:     const LocalInfo::LocalInfo\u0026 local_info, Event::Dispatcher\u0026 dispatcher,\n19:     Upstream::ClusterManager\u0026 cm, ProtobufMessage::ValidationVisitor\u0026 validation_visitor,\n20:     Api::Api\u0026 api, const Server::Instance\u0026 server,\n21:     XdsResourcesDelegateOptRef xds_resources_delegate, XdsConfigTrackerOptRef xds_config_tracker)\n22:     : local_info_(local_info), dispatcher_(dispatcher), cm_(cm),\n23:       validation_visitor_(validation_visitor), api_(api), server_(server),\n24:       xds_resources_delegate_(xds_resources_delegate), xds_config_tracker_(xds_config_tracker) {}\n25: \n26: absl::StatusOr\u003cSubscriptionPtr\u003e SubscriptionFactoryImpl::subscriptionFromConfigSource(\n27:     const envoy::config::core::v3::ConfigSource\u0026 config, absl::string_view type_url,\n28:     Stats::Scope\u0026 scope, SubscriptionCallbacks\u0026 callbacks,\n29:     OpaqueResourceDecoderSharedPtr resource_decoder, const SubscriptionOptions\u0026 options) {\n30:   RETURN_IF_NOT_OK(Config::Utility::checkLocalInfo(type_url, local_info_));\n31:   SubscriptionStats stats = Utility::generateStats(scope);\n32: \n33:   std::string subscription_type = \"\";\n34:   ConfigSubscriptionFactory::SubscriptionData data{local_info_,\n35:                                                    dispatcher_,\n36:                                                    cm_,\n37:                                                    validation_visitor_,\n38:                                                    api_,\n39:                                                    server_,\n40:                                                    xds_resources_delegate_,\n41:                                                    xds_config_tracker_,\n42:                                                    config,\n43:                                                    type_url,\n44:                                                    scope,\n45:                                                    callbacks,\n46:                                                    resource_decoder,\n47:                                                    options,\n48:                                                    absl::nullopt,\n49:                                                    stats};\n50: \n51:   switch (config.config_source_specifier_case()) {\n52:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kPath: {\n53:     RETURN_IF_NOT_OK(Utility::checkFilesystemSubscriptionBackingPath(config.path(), api_));\n54:     subscription_type = \"envoy.config_subscription.filesystem\";\n55:     break;\n56:   }\n57:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kPathConfigSource: {\n58:     RETURN_IF_NOT_OK(\n59:         Utility::checkFilesystemSubscriptionBackingPath(config.path_config_source().path(), api_));\n60:     subscription_type = \"envoy.config_subscription.filesystem\";\n61:     break;\n62:   }\n63:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kApiConfigSource: {\n64:     const envoy::config::core::v3::ApiConfigSource\u0026 api_config_source = config.api_config_source();\n65:     RETURN_IF_NOT_OK(Utility::checkApiConfigSourceSubscriptionBackingCluster(cm_.primaryClusters(),\n66:                                                                              api_config_source));\n67:     RETURN_IF_NOT_OK(Utility::checkTransportVersion(api_config_source));\n68:     switch (api_config_source.api_type()) {\n69:       PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;\n70:     case envoy::config::core::v3::ApiConfigSource::AGGREGATED_GRPC:\n71:       return absl::InvalidArgumentError(\"Unsupported config source AGGREGATED_GRPC\");\n72:     case envoy::config::core::v3::ApiConfigSource::AGGREGATED_DELTA_GRPC:\n73:       return absl::InvalidArgumentError(\"Unsupported config source AGGREGATED_DELTA_GRPC\");\n74:     case envoy::config::core::v3::ApiConfigSource::DEPRECATED_AND_UNAVAILABLE_DO_NOT_USE:\n75:       return absl::InvalidArgumentError(\n76:           \"REST_LEGACY no longer a supported ApiConfigSource. \"\n77:           \"Please specify an explicit supported api_type in the following config:\\n\" +\n78:           config.DebugString());\n79:     case envoy::config::core::v3::ApiConfigSource::REST:\n80:       subscription_type = \"envoy.config_subscription.rest\";\n81:       break;\n82:     case envoy::config::core::v3::ApiConfigSource::GRPC:\n83:       subscription_type = \"envoy.config_subscription.grpc\";\n84:       break;\n85:     case envoy::config::core::v3::ApiConfigSource::DELTA_GRPC:\n86:       subscription_type = \"envoy.config_subscription.delta_grpc\";\n87:       break;\n88:     }\n89:     if (subscription_type.empty()) {\n90:       return absl::InvalidArgumentError(\"Invalid API config source API type\");\n91:     }\n92:     break;\n93:   }\n94:   case envoy::config::core::v3::ConfigSource::ConfigSourceSpecifierCase::kAds: {\n95:     subscription_type = \"envoy.config_subscription.ads\";\n96:     break;\n97:   }\n98:   default:\n99:     return absl::InvalidArgumentError(\n100:         \"Missing config source specifier in envoy::config::core::v3::ConfigSource\");\n101:   }\n102:   ConfigSubscriptionFactory* factory =\n103:     