180:       }
181:       case envoy::config::core::v3::ApiConfigSource::AGGREGATED_GRPC:
182:         FALLTHRU;
183:       case envoy::config::core::v3::ApiConfigSource::AGGREGATED_DELTA_GRPC: {
184:         auto ptr_or_error =
185:             createFromFactory(data, "envoy.config_subscription.aggregated_grpc_collection");
186:         RETURN_IF_NOT_OK(ptr_or_error.status());
187:         return std::move(ptr_or_error.value());
188:       }
