{"meta": null, "content": [{"type": "text", "text": "{"content":"1: #include \"source/extensions/config_subscription/grpc/xds_mux/sotw_subscription_state.h\"\n2: \n3: #include \"source/common/config/utility.h\"\n4: #include \"source/extensions/config_subscription/grpc/xds_source_id.h\"\n5: \n6: namespace Envoy {\n7: namespace Config {\n8: namespace XdsMux {\n9: \n10: SotwSubscriptionState::SotwSubscriptionState(\n11:     std::string type_url, UntypedConfigUpdateCallbacks\u0026 callbacks, Event::Dispatcher\u0026 dispatcher,\n12:     OpaqueResourceDecoderSharedPtr resource_decoder, XdsConfigTrackerOptRef xds_config_tracker,\n13:     XdsResourcesDelegateOptRef xds_resources_delegate, const std::string\u0026 target_xds_authority)\n14:     : BaseSubscriptionState(std::move(type_url), callbacks, dispatcher, xds_config_tracker,\n15:                             xds_resources_delegate, target_xds_authority),\n16:       resource_decoder_(resource_decoder) {}\n17: \n18: SotwSubscriptionState::~SotwSubscriptionState() = default;\n19: \n20: void SotwSubscriptionState::updateSubscriptionInterest(\n21:     const absl::flat_hash_set\u003cstd::string\u003e\u0026 cur_added,\n22:     const absl::flat_hash_set\u003cstd::string\u003e\u0026 cur_removed) {\n23:   for (const auto\u0026 a : cur_added) {\n24:     names_tracked_.insert(a);\n25:   }\n26:   for (const auto\u0026 r : cur_removed) {\n27:     names_tracked_.erase(r);\n28:   }\n29:   if (!cur_added.empty() || !cur_removed.empty()) {\n30:     update_pending_ = true;\n31:   }\n32: }\n33: \n34: // Not having sent any requests yet counts as an \"update pending\" since you're supposed to resend\n35: // the entirety of your interest at the start of a stream, even if nothing has changed.\n36: bool SotwSubscriptionState::subscriptionUpdatePending() const {\n37:   return update_pending_ || dynamicContextChanged();\n38: }\n39: \n40: void SotwSubscriptionState::markStreamFresh() {\n41:   last_good_nonce_ = absl::nullopt;\n42:   update_pending_ = true;\n43:   clearDynamicContextChanged();\n44: }\n45: \n46: void SotwSubscriptionState::handleGoodResponse(\n47:     const envoy::service::discovery::v3::DiscoveryResponse\u0026 message) {\n48:   std::vector\u003cDecodedResourcePtr\u003e non_heartbeat_resources;\n49: \n50:   {\n51:     const auto scoped_update = ttl_.scopedTtlUpdate();\n52:     for (const auto\u0026 any : message.resources()) {\n53:       if (!any.Is\u003cenvoy::service::discovery::v3::Resource\u003e() \u0026\u0026\n54:           any.type_url() != message.type_url()) {\n55:         throw EnvoyException(fmt::format(\"type URL {} embedded in an individual Any does not match \"\n56:                                          \"the message-wide type URL {} in DiscoveryResponse {}\",\n57:                                          any.type_url(), message.type_url(),\n58:                                          message.DebugString()));\n59:       }\n60: \n61:       auto decoded_resource =\n62:           DecodedResourceImpl::fromResource(*resource_decoder_, any, message.version_info());\n63:       setResourceTtl(*decoded_resource);\n64:       if (isHeartbeatResource(*decoded_resource, message.version_info())) {\n65:         continue;\n66:       }\n67:       non_heartbeat_resources.push_back(std::move(decoded_resource));\n68:     }\n69:   }\n70: \n71:   // TODO (dmitri-d) to eliminate decoding of resources twice consider expanding the interface to\n72:   // support passing of decoded resources. This would also avoid a resource copy above.\n73:   callbacks().onConfigUpdate(non_heartbeat_resources, message.version_info());\n74:   // Now that we're passed onConfigUpdate() without an exception thrown, we know we're good.\n75:   last_good_version_info_ = message.version_info();\n76:   last_good_nonce_ = message.nonce();\n77: \n78:   // Processing point when resources are successfully ingested.\n79:   if (xds_config_tracker_.has_value()) {\n80:     xds_config_tracker_-\u003eonConfigAccepted(message.type_url(), non_heartbeat_resources);\n81:   }\n82: \n83:   // Send the resources to the xDS delegate, if configured.\n84:   if (xds_resources_delegate_.has_value()) {\n85:     XdsConfigSourceId source_id{target_xds_authority_, message.type_url()};\n86:     std::vector\u003cDecodedResourceRef\u003e resource_refs;\n87:     resource_refs.reserve(non_heartbeat_resources.size());\n88:     for (const DecodedResourcePtr\u0026 r : non_heartbeat_resources) {\n89:       resource_refs.emplace_back(*r);\n90:     }\n91:     xds_resources_delegate_-\u003eonConfigUpdated(source_id, resource_refs);\n92:   }\n93: \n94:   ENVOY_LOG(debug, \"Config update for {} (version {}) accepted with {} resources\", typeUrl(),\n95:             message.version_info(), message.resources().size());\n96: }\n97: \n98: void SotwSubscriptionState::handleEstablishmentFailure() {\n99:   BaseSubscriptionState::handleEstablishmentFailure();\n100: \n101:   if (previously_fetched_data_ || !xds_resources_delegate_.has_value()) {\n102:     return;\n103:   }\n104: \n105:   const XdsConfigSourceId source_id{target_xds_authority_, type_url_};\n106:   TRY_ASSERT_MAIN_THREAD {\n107:     std::vector\u003cenvoy::service::discovery::v3::Resource\u003e resources =\n108:         xds_resources_delegate_-\u003egetResources(source_id, names_tracked_);\n109: \n110:     std::vector\u003cDecodedResourcePtr\u003e decoded_resources;\n111:     const auto scoped_update = ttl_.scopedTtlUpdate();\n112:     std::string version_info;\n113:     size_t unaccounted = names_tracked_.size();\n114:     if (names_tracked_.size() == 1 \u0026\u0026 names_tracked_.contains(Envoy::Config::Wildcard)) {\n115:       // For wildcard requests, there are no expectations for the number of resources returned.\n116:       unaccounted = 0;\n117:     }\n118: \n119:     for (const auto\u0026 resource : resources) {\n120:       if (version_info.empty()) {\n121:         version_info = resource.version();\n122:       } else {\n123:         ASSERT(version_info == resource.version());\n124:       }\n125: \n126:       TRY_ASSERT_MAIN_THREAD {\n127:         auto decoded_resource = DecodedResourceImpl::fromResource(*resource_decoder_, resource);\n128:         setResourceTtl(*decoded_resource);\n129:         if (unaccounted \u003e 0) {\n130:           --unaccounted;\n131:         }\n132:         decoded_resources.emplace_back(std::move(decoded_resource));\n133:       }\n134:       END_TRY\n135:       catch (const EnvoyException\u0026 e) {\n136:         xds_resources_delegate_-\u003eonResourceLoadFailed(source_id, resource.name(), e);\n137:       }\n138:     }\n139: \n140:     callbacks().onConfigUpdate(decoded_resources, version_info);\n141:     previously_fetched_data_ = true;\n142:     if (unaccounted == 0 \u0026\u0026 !version_info.empty()) {\n143:       // All the requested resources were found and validated from the xDS delegate, so set the last\n144:       // known good version.\n145:       last_good_version_info_ = version_info;\n146:     }\n147:   }\n148:   END_TRY\n149:   catch (const EnvoyException\u0026 e) {\n150:     // TODO(abeyad): do something more than just logging the error?\n151:     ENVOY_LOG(warn, \"xDS delegate failed onEstablishmentFailure() for {}: {}\", source_id.toKey(),\n152:               e.what());\n153:   }\n154: }\n155: \n156: std::unique_ptr\u003cenvoy::service::discovery::v3::DiscoveryRequest\u003e\n157: SotwSubscriptionState::getNextRequestInternal() {\n158:   auto request = std::make_unique\u003cenvoy::service::discovery::v3::DiscoveryRequest\u003e();\n159:   request-\u003eset_type_url(typeUrl());\n160:   std::copy(names_tracked_.begin(), names_tracked_.end(),\n161:             Protobuf::RepeatedFieldBackInserter(request-\u003emutable_resource_names()));\n162:   if (last_good_version_info_.has_value()) {\n163:     request-\u003eset_version_info(last_good_version_info_.value());\n164:   }\n165:   // Default response_nonce to the last known good one. If we are being called by\n166:   // getNextRequestWithAck(), this value will be overwritten.\n167:   if (last_good_nonce_.has_value()) {\n168:     request-\u003eset_response_nonce(last_good_nonce_.value());\n169:   }\n170: \n171:   update_pending_ = false;\n172:   return request;\n173: }\n174: \n175: void SotwSubscriptionState::ttlExpiryCallback(const std::vector\u003cstd::string\u003e\u0026 expired) {\n176:   Protobuf::RepeatedPtrField\u003cstd::string\u003e removed_resources;\n177:   for (const auto\u0026 resource : expired) {\n178:     removed_resources.Add(std::string(resource));\n179:   }\n180:   callbacks().onConfigUpdate({}, removed_resources, \"\");\n181: }\n182: \n183: void SotwSubscriptionState::setResourceTtl(const DecodedResourceImpl\u0026 decoded_resource) {\n184:   if (decoded_resource.ttl()) {\n185:     ttl_.add(std::chrono::milliseconds(*decoded_resource.ttl()), decoded_resource.name());\n186:   } else {\n187:     ttl_.clear(decoded_resource.name());\n188:   }\n189: }\n190: \n191: bool SotwSubscriptionState::isHeartbeatResource(const DecodedResource\u0026 resource,\n192:                                                 const std::string\u0026 version) {\n193:   return !resource.hasResource() \u0026\u0026 last_good_version_info_.has_value() \u0026\u0026\n194:          version == last_good_version_info_.value();\n195: }\n196: \n197: } // namespace XdsMux\n198: } // namespace Config\n199: } // namespace Envoy\n200: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/envoy--v1.31.2@9fad78c5ca13df58ab7b58c0918b8986c9f01efb/-/blob/source/extensions/config_subscription/grpc/xds_mux/sotw_subscription_state.cc"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: #include "source/extensions/config_subscription/grpc/xds_mux/sotw_subscription_state.h"
